#!/bin/bash
set -e
echo "Setting up Market St HOA icon..."
mkdir -p public/icons

echo "" | base64 -d > public/icons/icon-16x16.png
echo "" | base64 -d > public/icons/favicon.png
echo "" | base64 -d > public/icons/icon-72x72.png
echo "" | base64 -d > public/icons/icon-96x96.png
echo "" | base64 -d > public/icons/icon-128x128.png
echo "" | base64 -d > public/icons/icon-144x144.png
echo "" | base64 -d > public/icons/icon-152x152.png
echo "" | base64 -d > public/icons/icon-192x192.png
echo "" | base64 -d > public/icons/icon-384x384.png
echo "" | base64 -d > public/icons/icon-512x512.png
echo "" | base64 -d > public/icons/apple-touch-icon.png

cat > public/icons/favicon.svg << 'SVGEOF'
<svg width="512" height="512" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg"><rect width="512" height="512" rx="92.16" fill="#111111"/><path d="M92.16,215.04 L92.16,419.84 L419.84000000000003,419.84 L419.84000000000003,215.04 L256.0,102.4 Z" fill="none" stroke="#ffffff" stroke-width="38.4" stroke-linejoin="round" stroke-linecap="round"/></svg>
SVGEOF

echo "✓ Icons written to public/icons/"

cat > public/manifest.json << 'MANIFESTEOF'
{
  "name": "HOA Portal - Market Street",
  "short_name": "HOA Portal",
  "description": "Homeowners Association management portal for Market Street community",
  "start_url": "/dashboard",
  "display": "standalone",
  "background_color": "#111111",
  "theme_color": "#111111",
  "orientation": "portrait-primary",
  "icons": [
    { "src": "/icons/icon-72x72.png",   "sizes": "72x72",   "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-72x72.png",   "sizes": "72x72",   "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-96x96.png",   "sizes": "96x96",   "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-96x96.png",   "sizes": "96x96",   "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-128x128.png", "sizes": "128x128", "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-128x128.png", "sizes": "128x128", "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-144x144.png", "sizes": "144x144", "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-144x144.png", "sizes": "144x144", "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-152x152.png", "sizes": "152x152", "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-152x152.png", "sizes": "152x152", "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-192x192.png", "sizes": "192x192", "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-192x192.png", "sizes": "192x192", "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-384x384.png", "sizes": "384x384", "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-384x384.png", "sizes": "384x384", "type": "image/png", "purpose": "maskable" },
    { "src": "/icons/icon-512x512.png", "sizes": "512x512", "type": "image/png", "purpose": "any" },
    { "src": "/icons/icon-512x512.png", "sizes": "512x512", "type": "image/png", "purpose": "maskable" }
  ],
  "categories": ["productivity", "business", "finance"],
  "shortcuts": [
    { "name": "Pay Dues", "short_name": "Pay", "url": "/payments", "icons": [{ "src": "/icons/icon-96x96.png", "sizes": "96x96" }] },
    { "name": "Documents", "short_name": "Docs", "url": "/documents", "icons": [{ "src": "/icons/icon-96x96.png", "sizes": "96x96" }] },
    { "name": "Voting", "short_name": "Vote", "url": "/voting", "icons": [{ "src": "/icons/icon-96x96.png", "sizes": "96x96" }] }
  ]
}
MANIFESTEOF
echo "✓ public/manifest.json updated"

# Patch src/layouts/Base.astro — update favicon links
python3 - << 'PYEOF'
import re
path = 'src/layouts/Base.astro'
with open(path) as f:
    src = f.read()

# Replace old favicon/manifest/apple links block
old = re.search(r'<link rel="manifest".*?<link rel="apple-touch-icon".*?/>', src, re.DOTALL)
if old:
    src = src[:old.start()] + '''<link rel="manifest" href="/manifest.json" />
    <link rel="icon" type="image/svg+xml" href="/icons/favicon.svg" />
    <link rel="icon" type="image/png" href="/icons/favicon.png" />
    <link rel="apple-touch-icon" sizes="180x180" href="/icons/apple-touch-icon.png" />''' + src[old.end():]

# Update theme-color meta
src = re.sub(r'<meta name="theme-color" content=".*?".*?/>', '<meta name="theme-color" content="#111111" />', src)

with open(path,'w') as f:
    f.write(src)
print("✓ src/layouts/Base.astro patched")
PYEOF

# Patch sidebar logo in src/layouts/App.astro
python3 - << 'PYEOF'
path = 'src/layouts/App.astro'
with open(path) as f:
    src = f.read()

old_logo = '<div class="w-8 h-8 bg-blue-600 rounded-md flex items-center justify-center text-white text-sm font-bold">M</div>'
new_logo = '''<svg width="32" height="32" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg"><rect width="32" height="32" rx="5.76" fill="#111111"/><path d="M5.76,13.44 L5.76,26.24 L26.24,26.24 L26.24,13.44 L16,6.4 Z" fill="none" stroke="white" stroke-width="2.4" stroke-linejoin="round" stroke-linecap="round"/></svg>'''

if old_logo in src:
    src = src.replace(old_logo, new_logo)
    with open(path,'w') as f:
        f.write(src)
    print("✓ src/layouts/App.astro logo patched")
else:
    print("⚠ Could not find logo mark in App.astro — patch manually")
PYEOF

# Patch landing page logo in src/pages/index.astro
python3 - << 'PYEOF'
path = 'src/pages/index.astro'
with open(path) as f:
    src = f.read()

old_logo = '<div class="w-8 h-8 bg-blue-600 rounded-md flex items-center justify-center text-white text-sm font-bold">M</div>'
new_logo = '''<svg width="32" height="32" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg"><rect width="32" height="32" rx="5.76" fill="#111111"/><path d="M5.76,13.44 L5.76,26.24 L26.24,26.24 L26.24,13.44 L16,6.4 Z" fill="none" stroke="white" stroke-width="2.4" stroke-linejoin="round" stroke-linecap="round"/></svg>'''

if old_logo in src:
    src = src.replace(old_logo, new_logo)
    with open(path,'w') as f:
        f.write(src)
    print("✓ src/pages/index.astro logo patched")
else:
    print("⚠ Could not find logo mark in index.astro — patch manually")
PYEOF

echo ""
echo "All done. Commit with: git add -A && git commit -m \"feat: premium icon system (The Frame)\""